/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 * Supports per-channel settings for email, SMS, and webhook delivery.
 *
 * Decision change (Session 9): The original model assumed email-only delivery.
 * With SMS added in Session 8 and webhook support available, this model now
 * supports per-channel preferences. Email defaults to enabled (preserving
 * backward compatibility), while SMS and webhook default to disabled
 * (opt-in only) to avoid surprising users.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': send as events occur
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Notification category — groups related notification types.
 * Maps to the prefix of NotificationType (e.g. 'order' covers
 * 'order:confirmation' and 'order:status-update').
 */
export type NotificationCategory = 'order' | 'user';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master toggle for all email notifications. */
  enabled: boolean;
  /** Delivery frequency for non-urgent emails. */
  frequency: EmailFrequency;
  /** Categories the user wants to receive. */
  subscribedCategories: NotificationCategory[];
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsPreferences {
  /** Master toggle for all SMS notifications. */
  enabled: boolean;
  /** Phone number for SMS delivery (E.164 format). */
  phoneNumber: string | null;
  /** Categories the user wants to receive via SMS. */
  subscribedCategories: NotificationCategory[];
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookPreferences {
  /** Master toggle for all webhook notifications. */
  enabled: boolean;
  /** Webhook endpoint URL. */
  url: string | null;
  /** Categories the user wants to receive via webhook. */
  subscribedCategories: NotificationCategory[];
}

/**
 * A user's full notification preferences across all channels.
 */
export interface UserNotificationPreferences {
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields are optional —
 * only provided fields are updated.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationCategory[];
}

/**
 * Input for updating SMS preferences. All fields are optional —
 * only provided fields are updated.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  phoneNumber?: string | null;
  subscribedCategories?: NotificationCategory[];
}

/**
 * Input for updating webhook preferences. All fields are optional —
 * only provided fields are updated.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  url?: string | null;
  subscribedCategories?: NotificationCategory[];
}

/**
 * Default email preferences for new users.
 * Email is enabled by default for backward compatibility.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: ['order', 'user'],
};

/**
 * Default SMS preferences for new users.
 * SMS is disabled by default — users must opt in.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  phoneNumber: null,
  subscribedCategories: ['order', 'user'],
};

/**
 * Default webhook preferences for new users.
 * Webhooks are disabled by default — users must opt in.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  url: null,
  subscribedCategories: ['order', 'user'],
};

/**
 * Extract the category from a notification type.
 * e.g. 'order:confirmation' -> 'order'
 */
export function getCategoryFromType(type: NotificationType): NotificationCategory {
  return type.split(':')[0] as NotificationCategory;
}

/**
 * Preferences service — manages user notification preferences across all channels.
 *
 * Stores preferences in-memory (matching the project's existing data layer
 * approach). Returns default preferences for users who haven't customized
 * their settings.
 *
 * Supports per-channel preferences for email, SMS, and webhook. Email defaults
 * to enabled (backward compatible), while SMS and webhook default to disabled.
 */

import type {
  UserNotificationPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
  getCategoryFromType,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get notification preferences for a user.
   * Returns default preferences if the user hasn't customized them.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return existing;
    }

    return {
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      updatedAt: new Date(),
    };
  }

  /**
   * Update email notification preferences for a user.
   * Merges provided fields with existing preferences.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      ...current,
      userId,
      email: {
        enabled: input.enabled ?? current.email.enabled,
        frequency: input.frequency ?? current.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...current.email.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated email preferences for user ${userId}`);

    return updated;
  }

  /**
   * Update SMS notification preferences for a user.
   * Merges provided fields with existing preferences.
   */
  updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      ...current,
      userId,
      sms: {
        enabled: input.enabled ?? current.sms.enabled,
        phoneNumber: input.phoneNumber !== undefined ? input.phoneNumber : current.sms.phoneNumber,
        subscribedCategories: input.subscribedCategories ?? [...current.sms.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated SMS preferences for user ${userId}`);

    return updated;
  }

  /**
   * Update webhook notification preferences for a user.
   * Merges provided fields with existing preferences.
   */
  updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      ...current,
      userId,
      webhook: {
        enabled: input.enabled ?? current.webhook.enabled,
        url: input.url !== undefined ? input.url : current.webhook.url,
        subscribedCategories: input.subscribedCategories ?? [...current.webhook.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated webhook preferences for user ${userId}`);

    return updated;
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   * Delegates to the appropriate channel-specific check.
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, notificationType);
      case 'sms':
        return this.shouldSendSms(userId, notificationType);
      case 'webhook':
        return this.shouldSendWebhook(userId, notificationType);
      default:
        return true;
    }
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if the user has email enabled and is subscribed to
   * the notification's category.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.email.enabled) {
      return false;
    }

    if (prefs.email.frequency === 'none') {
      return false;
    }

    const category = getCategoryFromType(notificationType);
    return prefs.email.subscribedCategories.includes(category);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   * Returns true if SMS is enabled, a phone number is set, and the
   * notification's category is subscribed.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.sms.enabled) {
      return false;
    }

    if (!prefs.sms.phoneNumber) {
      return false;
    }

    const category = getCategoryFromType(notificationType);
    return prefs.sms.subscribedCategories.includes(category);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   * Returns true if webhook is enabled, a URL is set, and the
   * notification's category is subscribed.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.webhook.enabled) {
      return false;
    }

    if (!prefs.webhook.url) {
      return false;
    }

    const category = getCategoryFromType(notificationType);
    return prefs.webhook.subscribedCategories.includes(category);
  }

  /**
   * Delete stored preferences for a user (reverts to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existed = this.preferences.has(userId);
    this.preferences.delete(userId);
    if (existed) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return existed;
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

/**
 * Notification service — orchestrates notification delivery via the EventBus
 * and registered NotificationAdapter implementations.
 *
 * Architecture:
 * - ALL notifications are triggered by AppEvents flowing through the EventBus.
 * - The NotificationService subscribes to relevant events and constructs
 *   NotificationPayloads from them.
 * - Each payload is dispatched to the appropriate NotificationAdapter based
 *   on its channel field.
 * - After delivery, the service emits notification:sent or notification:failed
 *   events for observability.
 * - Per-channel user preferences are checked before dispatching. If a user
 *   has disabled a channel or unsubscribed from the notification's category,
 *   the notification is suppressed for that channel.
 *
 * Constraints:
 * - All adapters MUST implement the NotificationAdapter interface.
 * - All notifications MUST go through EventBus.emit() — no direct calls.
 * - To add a new notification trigger, subscribe to the event in registerHandlers().
 * - To add a new delivery channel, implement NotificationAdapter and register it.
 *
 * Depends on:
 * - EventBus (event system) for receiving events and emitting delivery results
 * - NotificationAdapter implementations for actual delivery
 * - PreferencesService (optional) for checking per-channel user preferences
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (useful for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Set the preferences service used to check user notification preferences
   * before dispatching. When not set, all notifications are sent (backward-compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to EventBus events that trigger notifications.
   *
   * To add a new notification trigger:
   * 1. Define the event in src/events/event-types.ts
   * 2. Add a handler method that constructs a NotificationPayload
   * 3. Subscribe to the event here
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user via all enabled channels.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const subject = `Order Confirmation: ${event.order.id}`;
    const body = `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`;

    // Send via email
    if (this.isChannelAllowed(event.user.id, 'email', 'order:confirmation')) {
      this.logger.info(`Sending order confirmation for order ${event.order.id}`);
      const payload = this.buildPayload({
        type: 'order:confirmation',
        channel: 'email',
        recipient: event.user.email,
        subject,
        body,
        priority: 'normal',
      });
      void this.dispatch(payload);
    } else {
      this.logger.info(`Email suppressed by user preferences for order ${event.order.id}`);
    }

    // Send via SMS if adapter registered and preferences allow
    if (this.adapters.has('sms') && this.isChannelAllowed(event.user.id, 'sms', 'order:confirmation')) {
      const smsRecipient = this.getSmsRecipient(event.user.id);
      if (smsRecipient) {
        const payload = this.buildPayload({
          type: 'order:confirmation',
          channel: 'sms',
          recipient: smsRecipient,
          subject,
          body,
          priority: 'normal',
        });
        void this.dispatch(payload);
      }
    }

    // Send via webhook if adapter registered and preferences allow
    if (this.adapters.has('webhook') && this.isChannelAllowed(event.user.id, 'webhook', 'order:confirmation')) {
      const webhookUrl = this.getWebhookUrl(event.user.id);
      if (webhookUrl) {
        const payload = this.buildPayload({
          type: 'order:confirmation',
          channel: 'webhook',
          recipient: webhookUrl,
          subject,
          body,
          priority: 'normal',
        });
        void this.dispatch(payload);
      }
    }
  }

  /**
   * Handle order status change — notify user of update via all enabled channels.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const subject = `Order Update: ${event.order.id}`;
    const body = `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`;

    // Send via email
    if (this.isChannelAllowed(event.order.userId, 'email', 'order:status-update')) {
      this.logger.info(
        `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
      );
      const payload = this.buildPayload({
        type: 'order:status-update',
        channel: 'email',
        recipient: event.order.userId,
        subject,
        body,
        priority: 'normal',
      });
      void this.dispatch(payload);
    } else {
      this.logger.info(`Email suppressed by user preferences for order ${event.order.id}`);
    }

    // Send via SMS if adapter registered and preferences allow
    if (this.adapters.has('sms') && this.isChannelAllowed(event.order.userId, 'sms', 'order:status-update')) {
      const smsRecipient = this.getSmsRecipient(event.order.userId);
      if (smsRecipient) {
        const payload = this.buildPayload({
          type: 'order:status-update',
          channel: 'sms',
          recipient: smsRecipient,
          subject,
          body,
          priority: 'normal',
        });
        void this.dispatch(payload);
      }
    }

    // Send via webhook if adapter registered and preferences allow
    if (this.adapters.has('webhook') && this.isChannelAllowed(event.order.userId, 'webhook', 'order:status-update')) {
      const webhookUrl = this.getWebhookUrl(event.order.userId);
      if (webhookUrl) {
        const payload = this.buildPayload({
          type: 'order:status-update',
          channel: 'webhook',
          recipient: webhookUrl,
          subject,
          body,
          priority: 'normal',
        });
        void this.dispatch(payload);
      }
    }
  }

  /**
   * Check whether the user's preferences allow sending on a given channel.
   * Returns true if no preferences service is configured (backward-compatible).
   */
  private isChannelAllowed(userId: string, channel: NotificationChannel, type: NotificationType): boolean {
    if (!this.preferencesService) {
      return true;
    }
    return this.preferencesService.shouldSend(userId, channel, type);
  }

  /**
   * Get the SMS phone number for a user from their preferences.
   * Returns null if no phone number is configured.
   */
  private getSmsRecipient(userId: string): string | null {
    if (!this.preferencesService) {
      return null;
    }
    const prefs = this.preferencesService.getPreferences(userId);
    return prefs.sms.phoneNumber;
  }

  /**
   * Get the webhook URL for a user from their preferences.
   * Returns null if no URL is configured.
   */
  private getWebhookUrl(userId: string): string | null {
    if (!this.preferencesService) {
      return null;
    }
    const prefs = this.preferencesService.getPreferences(userId);
    return prefs.webhook.url;
  }

  /**
   * Build a full NotificationPayload from partial input.
   */
  private buildPayload(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): NotificationPayload {
    return {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };
  }

  /**
   * Dispatch a notification payload to the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  private async dispatch(payload: NotificationPayload): Promise<void> {
    // Always store the notification record
    this.storeNotification(payload);

    const adapter = this.adapters.get(payload.channel);
    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${payload.channel}", notification ${payload.id} stored but not delivered`,
      );
      return;
    }

    const result = await adapter.send(payload);

    if (result.success) {
      await this.eventBus.emit({
        type: 'notification:sent',
        payload,
        result,
        timestamp: new Date(),
      });
    } else {
      this.logger.error(`Notification ${payload.id} delivery failed: ${result.error}`);
      await this.eventBus.emit({
        type: 'notification:failed',
        payload,
        result,
        timestamp: new Date(),
      });
    }
  }

  /**
   * Store a notification record in-memory.
   */
  private storeNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: payload.id,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      priority: payload.priority,
      sentAt: payload.createdAt,
      metadata: payload.metadata,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification stored: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

