import { describe, it, expect, beforeEach } from 'vitest';
import { PreferencesService } from '../../src/services/preferences.service.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
  getCategoryFromType,
} from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let service: PreferencesService;

  beforeEach(() => {
    service = new PreferencesService();
  });

  describe('getPreferences', () => {
    it('should return default preferences for unknown user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should return default SMS preferences for unknown user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.phoneNumber).toBeNull();
      expect(prefs.sms.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should return default webhook preferences for unknown user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBeNull();
      expect(prefs.webhook.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should return stored preferences for known user', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should return independent copies of default preferences', () => {
      const prefs1 = service.getPreferences('user-1');
      const prefs2 = service.getPreferences('user-2');

      prefs1.email.subscribedCategories.push('order' as never);
      expect(prefs2.email.subscribedCategories).toEqual(DEFAULT_EMAIL_PREFERENCES.subscribedCategories);
    });
  });

  describe('updateEmailPreferences', () => {
    it('should update enabled flag', () => {
      const result = service.updateEmailPreferences('user-1', { enabled: false });

      expect(result.email.enabled).toBe(false);
      expect(result.email.frequency).toBe('immediate');
      expect(result.email.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should update frequency', () => {
      const result = service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });

      expect(result.email.frequency).toBe('daily-digest');
      expect(result.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      const result = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order'],
      });

      expect(result.email.subscribedCategories).toEqual(['order']);
    });

    it('should merge partial updates with existing preferences', () => {
      service.updateEmailPreferences('user-1', { frequency: 'weekly-digest' });
      const result = service.updateEmailPreferences('user-1', { enabled: false });

      expect(result.email.enabled).toBe(false);
      expect(result.email.frequency).toBe('weekly-digest');
    });

    it('should set updatedAt timestamp', () => {
      const before = new Date();
      const result = service.updateEmailPreferences('user-1', { enabled: false });

      expect(result.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });

    it('should preserve SMS and webhook preferences when updating email', () => {
      service.updateSmsPreferences('user-1', { enabled: true, phoneNumber: '+15551234567' });
      const result = service.updateEmailPreferences('user-1', { enabled: false });

      expect(result.email.enabled).toBe(false);
      expect(result.sms.enabled).toBe(true);
      expect(result.sms.phoneNumber).toBe('+15551234567');
    });
  });

  describe('updateSmsPreferences', () => {
    it('should update enabled flag and phone number', () => {
      const result = service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
      });

      expect(result.sms.enabled).toBe(true);
      expect(result.sms.phoneNumber).toBe('+15551234567');
      expect(result.sms.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should update subscribed categories', () => {
      const result = service.updateSmsPreferences('user-1', {
        subscribedCategories: ['order'],
      });

      expect(result.sms.subscribedCategories).toEqual(['order']);
    });

    it('should merge partial updates with existing SMS preferences', () => {
      service.updateSmsPreferences('user-1', { enabled: true, phoneNumber: '+15551234567' });
      const result = service.updateSmsPreferences('user-1', { subscribedCategories: ['order'] });

      expect(result.sms.enabled).toBe(true);
      expect(result.sms.phoneNumber).toBe('+15551234567');
      expect(result.sms.subscribedCategories).toEqual(['order']);
    });

    it('should allow clearing phone number', () => {
      service.updateSmsPreferences('user-1', { phoneNumber: '+15551234567' });
      const result = service.updateSmsPreferences('user-1', { phoneNumber: null });

      expect(result.sms.phoneNumber).toBeNull();
    });

    it('should preserve email preferences when updating SMS', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });
      const result = service.updateSmsPreferences('user-1', { enabled: true });

      expect(result.email.frequency).toBe('daily-digest');
      expect(result.sms.enabled).toBe(true);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should update enabled flag and URL', () => {
      const result = service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/webhook',
      });

      expect(result.webhook.enabled).toBe(true);
      expect(result.webhook.url).toBe('https://example.com/webhook');
      expect(result.webhook.subscribedCategories).toEqual(['order', 'user']);
    });

    it('should merge partial updates with existing webhook preferences', () => {
      service.updateWebhookPreferences('user-1', { enabled: true, url: 'https://example.com/hook' });
      const result = service.updateWebhookPreferences('user-1', { subscribedCategories: ['order'] });

      expect(result.webhook.enabled).toBe(true);
      expect(result.webhook.url).toBe('https://example.com/hook');
      expect(result.webhook.subscribedCategories).toEqual(['order']);
    });

    it('should allow clearing URL', () => {
      service.updateWebhookPreferences('user-1', { url: 'https://example.com/hook' });
      const result = service.updateWebhookPreferences('user-1', { url: null });

      expect(result.webhook.url).toBeNull();
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true for default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.updateEmailPreferences('user-1', { frequency: 'none' });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.updateEmailPreferences('user-1', { subscribedCategories: ['user'] });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(false);
    });

    it('should return true when category is subscribed', () => {
      service.updateEmailPreferences('user-1', { subscribedCategories: ['order'] });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'user:welcome')).toBe(false);
    });

    it('should handle all notification types correctly', () => {
      service.updateEmailPreferences('user-1', { subscribedCategories: ['order'] });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'user:welcome')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'user:profile-updated')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false for default preferences (SMS disabled by default)', () => {
      expect(service.shouldSendSms('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when SMS is enabled but no phone number is set', () => {
      service.updateSmsPreferences('user-1', { enabled: true });

      expect(service.shouldSendSms('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and phone number is set', () => {
      service.updateSmsPreferences('user-1', { enabled: true, phoneNumber: '+15551234567' });

      expect(service.shouldSendSms('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when category is not subscribed', () => {
      service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['user'],
      });

      expect(service.shouldSendSms('user-1', 'order:confirmation')).toBe(false);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false for default preferences (webhook disabled by default)', () => {
      expect(service.shouldSendWebhook('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when webhook is enabled but no URL is set', () => {
      service.updateWebhookPreferences('user-1', { enabled: true });

      expect(service.shouldSendWebhook('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled and URL is set', () => {
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/hook',
      });

      expect(service.shouldSendWebhook('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when category is not subscribed', () => {
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/hook',
        subscribedCategories: ['user'],
      });

      expect(service.shouldSendWebhook('user-1', 'order:confirmation')).toBe(false);
    });
  });

  describe('shouldSend (generic)', () => {
    it('should delegate to shouldSendEmail for email channel', () => {
      expect(service.shouldSend('user-1', 'email', 'order:confirmation')).toBe(true);

      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSend('user-1', 'email', 'order:confirmation')).toBe(false);
    });

    it('should delegate to shouldSendSms for sms channel', () => {
      expect(service.shouldSend('user-1', 'sms', 'order:confirmation')).toBe(false);

      service.updateSmsPreferences('user-1', { enabled: true, phoneNumber: '+15551234567' });
      expect(service.shouldSend('user-1', 'sms', 'order:confirmation')).toBe(true);
    });

    it('should delegate to shouldSendWebhook for webhook channel', () => {
      expect(service.shouldSend('user-1', 'webhook', 'order:confirmation')).toBe(false);

      service.updateWebhookPreferences('user-1', { enabled: true, url: 'https://example.com/hook' });
      expect(service.shouldSend('user-1', 'webhook', 'order:confirmation')).toBe(true);
    });

    it('should return true for unknown channels (forward-compatible)', () => {
      expect(service.shouldSend('user-1', 'in-app', 'order:confirmation')).toBe(true);
    });
  });

  describe('deletePreferences', () => {
    it('should return false for unknown user', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });

    it('should delete stored preferences and return true', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.deletePreferences('user-1')).toBe(true);

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
    });

    it('should revert all channel preferences to defaults', () => {
      service.updateSmsPreferences('user-1', { enabled: true, phoneNumber: '+15551234567' });
      service.updateWebhookPreferences('user-1', { enabled: true, url: 'https://example.com/hook' });

      service.deletePreferences('user-1');

      const prefs = service.getPreferences('user-1');
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.phoneNumber).toBeNull();
      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBeNull();
    });
  });

  describe('clearAll', () => {
    it('should clear all stored preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateEmailPreferences('user-2', { frequency: 'none' });

      service.clearAll();

      expect(service.getPreferences('user-1').email.enabled).toBe(true);
      expect(service.getPreferences('user-2').email.frequency).toBe('immediate');
    });
  });
});

describe('getCategoryFromType', () => {
  it('should extract order category', () => {
    expect(getCategoryFromType('order:confirmation')).toBe('order');
    expect(getCategoryFromType('order:status-update')).toBe('order');
  });

  it('should extract user category', () => {
    expect(getCategoryFromType('user:welcome')).toBe('user');
    expect(getCategoryFromType('user:profile-updated')).toBe('user');
  });
});

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesService = new PreferencesService();
    notificationService.setPreferencesService(preferencesService);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  it('should send notifications with default preferences', async () => {
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notifications when email is disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notifications when frequency is none', async () => {
    preferencesService.updateEmailPreferences('user-1', { frequency: 'none' });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notifications when category is unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['user'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send notifications when category is subscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress status-change notifications when order category unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['user'],
    });

    await eventBus.emit(statusChangedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send notifications when no preferences service is set', async () => {
    const serviceNoPrefs = new NotificationService(eventBus);
    serviceNoPrefs.registerAdapter(new EmailAdapter());

    await eventBus.emit(orderCreatedEvent);

    // Both services receive the event; the one without preferences should send
    expect(serviceNoPrefs.getNotificationCount()).toBe(1);
  });
});

describe('NotificationService multi-channel delivery', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesService = new PreferencesService();
    notificationService.setPreferencesService(preferencesService);
    emailAdapter = new EmailAdapter();
    smsAdapter = new SmsAdapter();
    webhookAdapter = new WebhookAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
    resetNotificationIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  it('should send to email only by default (SMS and webhook disabled)', async () => {
    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.channel).toBe('email');
  });

  it('should send to email and SMS when SMS is enabled', async () => {
    preferencesService.updateSmsPreferences('user-1', {
      enabled: true,
      phoneNumber: '+15551234567',
    });

    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
